#include<bits/stdc++.h>
using namespace std;
long long a, b, c=100003,n,m;
int main() {
	cin >> m >> n;
    a=m;
    b=n;
	long long x = b;
	long long lest = a%c;
	long long ans = 1 , ans2 = 1;
	while (x) {
		if (x % 2) {
			ans =ans*lest % c;
		}
		x /= 2;
		lest = (lest%c * lest%c) % c;
	}
    a=m-1;
    b=n-1;
	x = b;
	lest = a%c;
	while (x) {
		if (x % 2) {
			ans2 =ans2*lest % c;
		}
		x /= 2;
		lest = (lest%c * lest%c) % c;
	}
   ans2*=m;
    long long ans3=(ans-ans2)%c;
    while(ans3<0) ans3+=c;
	cout<<ans3;
	return 0;
}
